// 主题定义
export interface Theme {
  id: string;
  name: string;
  group: "flavor" | "simple" | "rich";
  // 颜色变量（8色协调）
  bg: string;            // 1. 页面背景
  bgDeep: string;      // 2. 深层背景
  text: string;        // 3. 主文字
  textSoft: string;    // 4. 次要文字
  accent: string;      // 5. 强调色（印章/按钮）
  accent2: string;     // 6. 辅助强调色
  card: string;        // 7. 卡片/气泡背景
  cardBorder: string;  // 8. 卡片边框
  myBubble: string;   // 我气泡
  myBubbleText?: string; // 我气泡文字颜色
  herCard: string;   // 他字卡底
  phoneShell: string;
  phoneScreen: string;
  // 渐变/装饰
  bgGradient?: string;
}

